"use client";

import { useState, useEffect, useRef } from "react";
import Link from "next/link";
import StepShell from "@/components/StepShell";
import { getRandomComplete, triggerShake } from "@/lib/learningMessages";

type Tab = "symmetry" | "rotation";

interface SymmetryShape {
  id: string;
  name: string;
  axes: number;
  render: (highlighted: number[]) => React.ReactNode;
}

const SHAPES: SymmetryShape[] = [
  {
    id: "rectangle",
    name: "长方形",
    axes: 2,
    render: (highlighted) => (
      <g transform="translate(100 80)">
        <rect x="-70" y="-45" width="140" height="90" fill="#FEF3C7" stroke="#F59E0B" strokeWidth="3" rx="4" />
        {/* 对称轴 1 - 水平 */}
        {highlighted.includes(0) && (
          <line x1="-75" y1="0" x2="75" y2="0" stroke="#E11D48" strokeWidth="2" strokeDasharray="6 4" />
        )}
        {/* 对称轴 2 - 垂直 */}
        {highlighted.includes(1) && (
          <line x1="0" y1="-50" x2="0" y2="50" stroke="#E11D48" strokeWidth="2" strokeDasharray="6 4" />
        )}
      </g>
    ),
  },
  {
    id: "square",
    name: "正方形",
    axes: 4,
    render: (highlighted) => (
      <g transform="translate(100 80)">
        <rect x="-55" y="-55" width="110" height="110" fill="#DBEAFE" stroke="#3B82F6" strokeWidth="3" rx="4" />
        {/* 对称轴 1 - 水平 */}
        {highlighted.includes(0) && (
          <line x1="-60" y1="0" x2="60" y2="0" stroke="#E11D48" strokeWidth="2" strokeDasharray="6 4" />
        )}
        {/* 对称轴 2 - 垂直 */}
        {highlighted.includes(1) && (
          <line x1="0" y1="-60" x2="0" y2="60" stroke="#E11D48" strokeWidth="2" strokeDasharray="6 4" />
        )}
        {/* 对称轴 3 - 对角线1 */}
        {highlighted.includes(2) && (
          <line x1="-55" y1="-55" x2="55" y2="55" stroke="#E11D48" strokeWidth="2" strokeDasharray="6 4" />
        )}
        {/* 对称轴 4 - 对角线2 */}
        {highlighted.includes(3) && (
          <line x1="55" y1="-55" x2="-55" y2="55" stroke="#E11D48" strokeWidth="2" strokeDasharray="6 4" />
        )}
      </g>
    ),
  },
  {
    id: "circle",
    name: "圆形",
    axes: 10, // 需要画 10 条对称轴才能理解"无数条"的概念
    render: (highlighted) => {
      const lines = highlighted.map((i) => {
        const angle = (i * 18 * Math.PI) / 180; // 每 18° 一条
        const r = 60;
        const x1 = Math.cos(angle) * r;
        const y1 = Math.sin(angle) * r;
        const x2 = -Math.cos(angle) * r;
        const y2 = -Math.sin(angle) * r;
        return <line key={i} x1={x1} y1={y1} x2={x2} y2={y2} stroke="#E11D48" strokeWidth="2" strokeDasharray="6 4" opacity={0.6 + i * 0.04} />;
      });
      return (
        <g transform="translate(100 80)">
          <circle cx="0" cy="0" r="55" fill="#DCFCE7" stroke="#22C55E" strokeWidth="3" />
          {lines}
          {highlighted.length >= 10 && (
            <text x="0" y="5" textAnchor="middle" fill="#166534" fontSize="12" fontWeight="bold">
              无数条！
            </text>
          )}
        </g>
      );
    },
  },
];

const ROTATION_QUESTIONS = [
  {
    id: 1,
    question: "钟表的指针是怎么转的？",
    icon: "⏰",
    options: ["顺时针", "逆时针", "不转"],
    answer: 0,
    hint: "看看钟表的指针，1→2→3→...是往哪个方向？",
  },
  {
    id: 2,
    question: "风车顺时针转了几圈？",
    icon: "🎡",
    type: "count",
    answer: 3,
    spins: 3,
  },
  {
    id: 3,
    question: "电风扇转了几圈？",
    icon: "🌀",
    type: "count",
    answer: 5,
    spins: 5,
  },
];

export default function CountPage() {
  const [tab, setTab] = useState<Tab>("symmetry");
  const [completeMsg, setCompleteMsg] = useState("");
  useEffect(() => { setCompleteMsg(getRandomComplete()); }, []);

  // 轴对称部分
  const [shapeIndex, setShapeIndex] = useState(0);
  const [highlightedAxes, setHighlightedAxes] = useState<number[]>([]);
  const [symmetryDone, setSymmetryDone] = useState(false);

  // 旋转部分
  const [rotIndex, setRotIndex] = useState(0);
  const [rotCorrect, setRotCorrect] = useState(0);
  const [rotationDone, setRotationDone] = useState(false);

  const currentShape = SHAPES[shapeIndex];

  const handleAddAxis = () => {
    if (highlightedAxes.length < currentShape.axes) {
      setHighlightedAxes([...highlightedAxes, highlightedAxes.length]);
    }
  };

  const handleNextShape = () => {
    if (shapeIndex < SHAPES.length - 1) {
      setShapeIndex(shapeIndex + 1);
      setHighlightedAxes([]);
    } else {
      setSymmetryDone(true);
    }
  };

  const handleRotAnswer = (value: number) => {
    const q = ROTATION_QUESTIONS[rotIndex];
    if (value === q.answer) {
      setRotCorrect(rotCorrect + 1);
      if (rotIndex < ROTATION_QUESTIONS.length - 1) {
        setTimeout(() => setRotIndex(rotIndex + 1), 500);
      } else {
        setRotationDone(true);
      }
    } else {
      const el = document.getElementById("rot-question");
      triggerShake(el);
    }
  };

  const allDone = symmetryDone && rotationDone;

  return (
    <StepShell topicId="motion" stepId="count">
      <div className="space-y-5">
        {/* 标签切换 */}
        <div className="flex justify-center gap-2">
          <button
            onClick={() => setTab("symmetry")}
            className={`rounded-full px-5 py-2 text-sm font-medium transition-all ${
              tab === "symmetry"
                ? "bg-[var(--bg-card)] text-[var(--text)] shadow-[var(--shadow-sm)]"
                : "text-[var(--text-secondary)] hover:bg-[var(--bg-card)]/60"
            }`}
          >
            📐 数对称轴
            {symmetryDone && <span className="ml-1 text-[var(--signal-success)]">✓</span>}
          </button>
          <button
            onClick={() => setTab("rotation")}
            className={`rounded-full px-5 py-2 text-sm font-medium transition-all ${
              tab === "rotation"
                ? "bg-[var(--bg-card)] text-[var(--text)] shadow-[var(--shadow-sm)]"
                : "text-[var(--text-secondary)] hover:bg-[var(--bg-card)]/60"
            }`}
          >
            🎡 数旋转
            {rotationDone && <span className="ml-1 text-[var(--signal-success)]">✓</span>}
          </button>
        </div>

        {/* 数对称轴 */}
        {tab === "symmetry" && !symmetryDone && (
          <section className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
            <div className="text-center">
              <h3 className="text-lg font-bold text-[var(--text)]">
                第 {shapeIndex + 1} / {SHAPES.length} 个图形
              </h3>
              <p className="mt-1 text-sm text-[var(--text-secondary)]">
                {currentShape.name}有几条对称轴？点一点看看
              </p>
            </div>

            {/* 图形展示 */}
            <div className="mt-6 flex justify-center">
              <svg viewBox="0 0 200 160" className="w-52 h-40">
                {currentShape.render(highlightedAxes)}
              </svg>
            </div>

            {/* 对称轴计数 */}
            <div className="mt-4 text-center">
              <p className="text-sm text-[var(--text-secondary)]">
                {currentShape.id === "circle" && highlightedAxes.length >= 10
                  ? "圆形有无数条对称轴，已画了 10 条！"
                  : `已画出 ${highlightedAxes.length} / ${currentShape.axes} 条对称轴`}
              </p>
            </div>

            {/* 操作按钮 */}
            <div className="mt-5 flex flex-wrap justify-center gap-3">
              <button
                onClick={handleAddAxis}
                disabled={highlightedAxes.length >= currentShape.axes}
                className="rounded-full bg-[var(--primary)] px-6 py-2 text-sm font-bold text-white shadow-[var(--shadow-sm)] transition-all hover:scale-105 disabled:opacity-40"
              >
                + 画一条对称轴
              </button>
              {highlightedAxes.length >= currentShape.axes && (
                <button
                  onClick={handleNextShape}
                  className="rounded-full bg-[var(--accent)] px-6 py-2 text-sm font-bold text-white shadow-[var(--shadow-accent)] transition-all hover:scale-105"
                >
                  {shapeIndex < SHAPES.length - 1 ? "下一个图形 →" : "完成 ✓"}
                </button>
              )}
            </div>

            {/* 提示 */}
            {highlightedAxes.length === 0 && (
              <p className="mt-4 text-center text-xs text-[var(--text-muted)]">
                💡 提示：对称轴就是对折后两边能完全重合的那条线
              </p>
            )}
          </section>
        )}

        {/* 数旋转 */}
        {tab === "rotation" && !rotationDone && (
          <section id="rot-question" className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
            <div className="text-center">
              <p className="text-xs text-[var(--text-muted)]">
                第 {rotIndex + 1} / {ROTATION_QUESTIONS.length} 题
              </p>
              <div className="mt-2 text-5xl">{ROTATION_QUESTIONS[rotIndex].icon}</div>
              <h3 className="mt-3 text-lg font-bold text-[var(--text)]">
                {ROTATION_QUESTIONS[rotIndex].question}
              </h3>
            </div>

            {/* 选项 / 计数 */}
            <div className="mt-6">
              {"options" in ROTATION_QUESTIONS[rotIndex] ? (
                <div className="space-y-2">
                  {ROTATION_QUESTIONS[rotIndex].options?.map((opt, i) => (
                    <button
                      key={i}
                      onClick={() => handleRotAnswer(i)}
                      className="w-full rounded-lg border-2 border-[var(--border)] bg-[var(--bg-soft)] px-4 py-3 text-left text-sm font-medium text-[var(--text)] transition-all hover:border-[var(--primary)] hover:bg-[var(--primary)]/10"
                    >
                      {String.fromCharCode(65 + i)}. {opt}
                    </button>
                  ))}
                </div>
              ) : (
                <RotationCounter
                  spins={ROTATION_QUESTIONS[rotIndex].spins || 3}
                  onAnswer={handleRotAnswer}
                  answer={ROTATION_QUESTIONS[rotIndex].answer || 3}
                />
              )}
            </div>

            <p className="mt-4 text-center text-xs text-[var(--text-muted)]">
              答对 {rotCorrect} 题
            </p>
          </section>
        )}

        {/* 对称完成卡片 */}
        {tab === "symmetry" && symmetryDone && (
          <section className="animate-float-in rounded-[var(--radius)] border-2 border-[var(--signal-success)] bg-[var(--bg-card)] p-6 text-center shadow-[var(--shadow-md)]">
            <div className="text-4xl">📐</div>
            <h3 className="mt-3 text-lg font-bold text-[var(--text)]">
              对称轴数完啦！
            </h3>
            <p className="mt-2 text-sm text-[var(--text-secondary)]">
              长方形有 2 条，正方形有 4 条，圆形有无数条！
            </p>
            {!rotationDone && (
              <button
                onClick={() => setTab("rotation")}
                className="mt-5 rounded-full bg-[var(--accent)] px-6 py-2 text-sm font-bold text-white shadow-[var(--shadow-accent)] transition-all hover:scale-105"
              >
                去数旋转 →
              </button>
            )}
          </section>
        )}

        {/* 旋转完成卡片 */}
        {tab === "rotation" && rotationDone && (
          <section className="animate-float-in rounded-[var(--radius)] border-2 border-[var(--signal-success)] bg-[var(--bg-card)] p-6 text-center shadow-[var(--shadow-md)]">
            <div className="text-4xl">🎡</div>
            <h3 className="mt-3 text-lg font-bold text-[var(--text)]">
              旋转也数完啦！
            </h3>
            <p className="mt-2 text-sm text-[var(--text-secondary)]">
              钟表指针是顺时针转的，转一圈就是 360 度！
            </p>
            {!symmetryDone && (
              <button
                onClick={() => setTab("symmetry")}
                className="mt-5 rounded-full bg-[var(--primary)] px-6 py-2 text-sm font-bold text-white shadow-[var(--shadow-sm)] transition-all hover:scale-105"
              >
                去数对称轴 →
              </button>
            )}
          </section>
        )}

        {/* 全部完成 */}
        {allDone && (
          <section className="animate-float-in rounded-[var(--radius)] border-2 border-[var(--signal-success)] bg-[var(--bg-card)] p-6 text-center shadow-[var(--shadow-md)]">
            <div className="text-5xl animate-bounce-soft">🔢</div>
            <h2 className="mt-3 text-xl font-bold text-[var(--text)]">
              {completeMsg}
            </h2>
            <p className="mt-2 text-[var(--text-secondary)]">
              你学会了数对称轴和判断旋转方向！
            </p>
            <div className="mt-6 flex flex-wrap justify-center gap-3">
              <Link
                href="/learn/motion/draw"
                className="rounded-full bg-[var(--accent)] px-6 py-3 text-sm font-bold text-white shadow-[var(--shadow-accent)] transition-all hover:-translate-y-0.5 hover:shadow-[var(--shadow-md)]"
              >
                下一步：画一画 →
              </Link>
            </div>
          </section>
        )}
      </div>
    </StepShell>
  );
}

// ========== 旋转计数组件 ==========
function RotationCounter({
  spins,
  onAnswer,
  answer,
}: {
  spins: number;
  onAnswer: (value: number) => void;
  answer: number;
}) {
  const [rotation, setRotation] = useState(0);
  const [isSpinning, setIsSpinning] = useState(false);
  const [showAnswer, setShowAnswer] = useState(false);

  // 用 useRef 固定选项顺序，避免每次 render 重新随机
  const shuffledRef = useRef<number[]>([]);
  if (shuffledRef.current.length === 0) {
    const options = [answer - 1, answer, answer + 1, answer + 2].filter((n) => n > 0);
    shuffledRef.current = [...options].sort(() => Math.random() - 0.5);
  }
  const shuffled = shuffledRef.current;

  const startSpin = () => {
    if (isSpinning) return;
    setIsSpinning(true);
    setShowAnswer(false);

    const target = spins * 360;
    const duration = 3000;
    const startTime = performance.now();
    const startRot = rotation;

    const animate = (now: number) => {
      const elapsed = now - startTime;
      const progress = Math.min(elapsed / duration, 1);
      const easeOut = 1 - Math.pow(1 - progress, 3);
      const current = startRot + target * easeOut;
      setRotation(current);

      if (progress < 1) {
        requestAnimationFrame(animate);
      } else {
        setIsSpinning(false);
        setShowAnswer(true);
      }
    };

    requestAnimationFrame(animate);
  };

  return (
    <div className="space-y-4">
      {/* 旋转的风车 */}
      <div className="flex justify-center">
        <div
          className="cursor-pointer"
          onClick={startSpin}
          style={{
            transform: `rotate(${rotation}deg)`,
            transition: isSpinning ? "none" : "transform 0.3s",
          }}
        >
          <svg viewBox="0 0 120 120" className="w-28 h-28">
            <g transform="translate(60 60)">
              <path d="M 0 0 L 0 -45 Q 18 -40 25 -25 Q 22 -10 0 -3 Z" fill="#FB7185" opacity="0.85" />
              <path d="M 0 0 L 45 0 Q 40 18 25 25 Q 10 22 3 0 Z" fill="#38BDF8" opacity="0.85" />
              <path d="M 0 0 L 0 45 Q -18 40 -25 25 Q -22 10 0 3 Z" fill="#FBBF24" opacity="0.85" />
              <path d="M 0 0 L -45 0 Q -40 -18 -25 -25 Q -10 -22 -3 0 Z" fill="#34D399" opacity="0.85" />
              <circle cx="0" cy="0" r="8" fill="#F59E0B" />
            </g>
          </svg>
        </div>
      </div>

      <p className="text-center text-xs text-[var(--text-muted)]">
        点风车开始转，数一数转了几圈 👆
      </p>

      {showAnswer && (
        <div className="animate-float-in space-y-2">
          <p className="text-center text-sm font-medium text-[var(--text)]">
            转了几圈？
          </p>
          <div className="grid grid-cols-4 gap-2">
            {shuffled.map((n) => (
              <button
                key={n}
                onClick={() => onAnswer(n)}
                className="rounded-lg border-2 border-[var(--border)] bg-[var(--bg-soft)] py-3 text-lg font-bold text-[var(--text)] transition-all hover:border-[var(--primary)] hover:bg-[var(--primary)]/10"
              >
                {n}
              </button>
            ))}
          </div>
          <button
            onClick={startSpin}
            className="w-full rounded-lg py-2 text-sm text-[var(--text-secondary)] hover:bg-[var(--bg-soft)]"
          >
            🔄 再看一次
          </button>
        </div>
      )}

      {!showAnswer && !isSpinning && (
        <div className="flex justify-center">
          <button
            onClick={startSpin}
            className="rounded-full bg-[var(--accent)] px-6 py-2 text-sm font-bold text-white shadow-[var(--shadow-accent)] transition-all hover:scale-105"
          >
            开始转动 🌀
          </button>
        </div>
      )}
    </div>
  );
}
